previewCss:
.darma-loader-darma-custom-615 {color: var(--loader-color, #be123c);
  --loader-secondary-color: var(--loader-secondary-color, #fda4af);
  --loader-bg: var(--loader-bg, #ffffff);
   width: 68px;
   aspect-ratio: 1;
   border: 8px solid #0000;
   box-sizing: border-box;
   background: radial-gradient(farthest-side,currentColor 98%,#0000) 0 0/20px 20px, radial-gradient(farthest-side,currentColor 98%,#0000) 100% 0/20px 20px, radial-gradient(farthest-side,currentColor 98%,#0000) 100% 100%/20px 20px, radial-gradient(farthest-side,currentColor 98%,#0000) 0 100%/20px 20px, linear-gradient(currentColor 0 0) 50%/40px 40px, currentColor;
   background-repeat:no-repeat;
   filter: blur(4px) contrast(10);
   animation: darma-loader-darma-custom-615-l12 0.8s infinite;
}
@keyframes darma-loader-darma-custom-615-l12  {
  100% {background-position:100% 0,100% 100%,0 100%,0 0,center}
}

